  bloom += sampleBright(uv + vec2(-texel.x * 2.0, 0.0)) * 0.04;
  bloom += sampleBright(uv + vec2(0.0,  texel.y * 2.0)) * 0.04;
  bloom += sampleBright(uv + vec2(0.0, -texel.y * 2.0)) * 0.04;

